class LoopInfinite {
    public static function main(): Void {
        var b: Int = 69;
        do {
            b *= 2;
        } while (b <= 1000);
    }
}

original.content:
class LoopNested {
    static function main() {
        var b = 69;
        while (true) {
            b *= 2;
            if (b &gt; 1000) {
                break;
            }
            var a = 0;
            if (a &gt; 1) {
                a = 1;
            } else {
                a = 2;
                return;
            }
            while (true) {
                b *= 2;
                if (b &gt; 1000) {
                    break;
                }
            }
        }
    }
}

